"""Simple business rule engine."""
from typing import Any, Dict, List

OPERATORS = {
    "eq": lambda a, b: a == b,
    "neq": lambda a, b: a != b,
    "gt": lambda a, b: a > b,
    "lt": lambda a, b: a < b,
    "gte": lambda a, b: a >= b,
    "lte": lambda a, b: a <= b,
    "contains": lambda a, b: b in a,
}


def evaluate_condition(condition: Dict, context: Dict[str, Any]) -> bool:
    field = condition["field"]
    operator = condition["operator"]
    value = condition["value"]
    actual = context.get(field)
    if actual is None:
        return False
    op_fn = OPERATORS.get(operator)
    if not op_fn:
        raise ValueError(f"Unknown operator: {operator}")
    return op_fn(actual, value)


def evaluate_rules(
    rules: List[Dict], context: Dict[str, Any]
) -> List[Dict]:
    """Evaluate rules against context. Returns matched rule actions."""
    matched = []
    for rule in rules:
        conditions = rule.get("conditions", [])
        all_match = all(
            evaluate_condition(c, context) for c in conditions
        )
        if all_match:
            matched.append({
                "rule": rule["name"],
                "action": rule["action"],
            })
    return matched
